#include <stdio.h>
#include <string.h>
#include <stdbool.h>
#define MAXN 105
#define MAXLEN 6
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,K; scanf("%d %d",&N,&K);
        char dict[MAXN][MAXLEN];
        bool present[MAXN];
        for(int i=0;i<N;i++){
            scanf("%s",dict[i]);
            present[i]=false;
        }
        // read all phrases and mark presence
        for(int i=0;i<K;i++){
            int L; scanf("%d",&L);
            for(int j=0;j<L;j++){
                char w[MAXLEN]; scanf("%s",w);
                for(int d=0; d<N; d++) if(!present[d] && strcmp(w,dict[d])==0) present[d]=true;
            }
        }
        for(int i=0;i<N;i++){
            printf(present[i]?"YES":"NO");
            if(i+1<N) printf(" ");
        }
        if(T) printf("\n");
    }
    return 0;
}

