import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        dict_words = [next(it) for _ in range(N)]
        used = set()
        for _ in range(K):
            L = int(next(it))
            for _ in range(L):
                used.add(next(it))
        out_lines.append(' '.join('YES' if w in used else 'NO' for w in dict_words))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

