const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const K = Number(input[idx++]);
  const dict = [];
  for (let i = 0; i < N; i++) dict.push(input[idx++]);
  const used = new Set();
  for (let i = 0; i < K; i++) {
    const L = Number(input[idx++]);
    for (let j = 0; j < L; j++) used.add(input[idx++]);
  }
  const line = dict.map(w => used.has(w) ? 'YES' : 'NO').join(' ');
  outputs.push(line);
}
console.log(outputs.join('\n'));

